sql:
SELECT sale_id, sale_date, quantity_sold, revenue
FROM sales
ORDER BY sale_id;

external_knowledge:
- "voyaged above the sea of average sales performance" metaphorically denotes achieving an average revenue above the general or overall average;
- "luminaries in their financial journey" metaphorically refers to brands and regions that are performing exceptionally well financially.
- "order of luminosity" is used here to indicate sorting by average revenue in descending order.

sql:
SELECT brands.brand_name, sales.sale_type
FROM brands
JOIN sales ON brands.brand_id = sales.brand_id;

SELECT AVG(sales_count) AS average_sales_per_brand
FROM (
    SELECT brand_id, COUNT(sale_id) AS sales_count
    FROM sales
    GROUP BY brand_id
);
